fn ecommercepanel_init_data() {
    ECOMMERCEPANEL_STATE.with(|s| {
        let mut state = s.borrow_mut();
        state.status = format!("Fetching 10,000 products from API...");
    });
}

fn ecommercepanel_on_data_loaded() {
    let _op_t0 = perf_now();
    ECOMMERCEPANEL_STATE.with(|s| {
        let mut state = s.borrow_mut();
        state.product_count = state.products.len() as i32;
        state.status = format!("{} products fetched from database", state.product_count);
    });
    ECOMMERCEPANEL_STATE.with(|s| s.borrow_mut().heap_ms = honeycomb::canvas_app::get_heap_ms());
    // Re-render after state change
    let _t_rebuild = perf_now();
    // Clear stale registrations before tree rebuild
    honeycomb::canvas_app::clear_registrations();
    with_tree(|tree| {
        let root = tree.root_id();
        if let Some(el) = tree.get_mut(root) { el.children.clear(); }
    });
    ecommercepanel_mount();
    let _t_mounted = perf_now();
    render();
    let _t_laid = perf_now();
    {
        let msg = format!("REBUILD mount={:.2}ms layout={:.2}ms", _t_mounted - _t_rebuild, _t_laid - _t_mounted);
        unsafe { console_log(msg.as_ptr(), msg.len() as u32); }
    }
    let _total = to_ms_string(unsafe { INIT_START }, perf_now());
    ECOMMERCEPANEL_STATE.with(|s| s.borrow_mut().total_ms = _total.clone());
    update_metric_text("total_ms", &_total);
    let _pc = ECOMMERCEPANEL_STATE.with(|s| format!("{}", s.borrow().product_count));
    update_metric_text("product_count", &_pc);
}

fn ecommercepanel_add_to_cart() {
    let _op_t0 = perf_now();
    ECOMMERCEPANEL_STATE.with(|s| {
        let mut state = s.borrow_mut();
        state.cart_count = (state.cart_count + 1);
    });
    // Simple state update — targeted text binding updates (no tree rebuild)
    { let _val = ECOMMERCEPANEL_STATE.with(|s| format!("{}", s.borrow().cart_count)); honeycomb::canvas_app::update_text_bindings("cart_count", &_val); }
    honeycomb::canvas_app::mark_gpu_dirty();
    let _op_elapsed = to_ms_string(_op_t0, perf_now());
    ECOMMERCEPANEL_STATE.with(|s| s.borrow_mut().last_op_ms = _op_elapsed.clone());
    update_metric_text("last_op_ms", &_op_elapsed);
}

