// ── Render: layout only (painting done by Honeycomb's app_render) ──

fn render() {
    honeycomb::wasm_api::TREE.with(|t| {
        let mut tree = t.borrow_mut();
        let mut measurer = EstimateMeasurer;
        let vw = unsafe { canvas_get_width() };
        let vh = unsafe { canvas_get_height() };
        layout::compute(&mut tree, vw, 999999.0, &mut measurer);
    });
}

#[no_mangle]
pub extern "C" fn nectar_init(_vw: f32, _vh: f32) {
    let _init_t0 = perf_now();
    unsafe { INIT_START = _init_t0; }
    ecommercepanel_init_data();
    ecommercepanel_mount();
    let _init_elapsed = to_ms_string(_init_t0, perf_now());
    ECOMMERCEPANEL_STATE.with(|s| s.borrow_mut().total_ms = _init_elapsed.clone());
    update_metric_text("total_ms", &_init_elapsed);
    let _heap = ECOMMERCEPANEL_STATE.with(|s| s.borrow().heap_ms.clone());
    update_metric_text("heap_ms", &_heap);
    // Auto-fetch: init_data detected, firing fetch with callback
    fetch_get("/api/products?per_page=10000", 0);
}

#[no_mangle]
pub extern "C" fn __callback(idx: u32) {
    if idx == 0 {
        // Zero-copy JSON parse: leak response buffer so Product borrows &'static str
        let _t_copy = perf_now();
        let (_status, body) = read_response();
        let body: &'static [u8] = Box::leak(body.into_boxed_slice());
        let _t_copied = perf_now();
        ECOMMERCEPANEL_STATE.with(|s| {
            let mut state = s.borrow_mut();
            if let Ok(parsed) = serde_json::from_slice::<Vec<Product>>(&body) {
                state.products = parsed;
            }
        });
        let _t_parsed = perf_now();
        {
            let msg = format!("FETCH BREAKDOWN: copy={:.2}ms serde_parse={:.2}ms body={}bytes", _t_copied - _t_copy, _t_parsed - _t_copied, body.len());
            unsafe { console_log(msg.as_ptr(), msg.len() as u32); }
        }
    }
    match idx {
        0 => ecommercepanel_on_data_loaded(),
        1 => ecommercepanel_add_to_cart(),
        2 => ecommercepanel_toggle_cart(),
        3 => ecommercepanel_close_cart(),
        4 => ecommercepanel_checkout(),
        5 => ecommercepanel_cat_all(),
        6 => ecommercepanel_cat_electronics(),
        7 => ecommercepanel_cat_clothing(),
        8 => ecommercepanel_cat_home(),
        9 => ecommercepanel_cat_sports(),
        10 => ecommercepanel_cat_books(),
        11 => ecommercepanel_sort_price_asc(),
        12 => ecommercepanel_sort_price_desc(),
        13 => ecommercepanel_sort_name(),
        _ => {}
    }
}
